  1→import { render, screen } from '@testing-library/react';
  2→import userEvent from '@testing-library/user-event';
  3→import { describe, expect, it, vi } from 'vitest';
  4→import { List } from './list';
  5→import { ListItem } from './list_item/list_item';
  6→
  7→function renderList(props: {
  8→  itemCount?: number;
  9→  onActiveIndexChange?: (i: number) => void;
 10→  onAction?: (i: number) => void;
 11→}) {
 12→  const count = props.itemCount ?? 3;
 13→  return render(
 14→    <List
 15→      itemCount={count}
 16→      onActiveIndexChange={props.onActiveIndexChange}
 17→      onAction={props.onAction}
 18→    >
 19→      {Array.from({ length: count }, (_, i) => (
 20→        <ListItem key={i} index={i} title={`Item ${i}`} />
 21→      ))}
 22→    </List>,
 23→  );
 24→}
 25→
 26→describe('List', () => {
 27→  it('renders a listbox with items', () => {
 28→    renderList({});
 29→    expect(screen.getByRole('listbox')).toBeInTheDocument();
 30→    expect(screen.getAllByRole('option')).toHaveLength(3);
 31→  });
 32→
 33→  it('first item is active by default', () => {
 34→    renderList({});
 35→    const items = screen.getAllByRole('option');
 36→    expect(items[0]).toHaveAttribute('aria-selected', 'true');
 37→    expect(items[1]).toHaveAttribute('aria-selected', 'false');
 38→  });
 39→
 40→  it('ArrowDown moves active index forward', async () => {
 41→    const user = userEvent.setup();
 42→    const onChange = vi.fn();
 43→    renderList({ onActiveIndexChange: onChange });
 44→
 45→    await user.keyboard('{ArrowDown}');
 46→    expect(onChange).toHaveBeenCalledWith(1);
 47→
 48→    const items = screen.getAllByRole('option');
 49→    expect(items[1]).toHaveAttribute('aria-selected', 'true');
 50→  });
 51→
 52→  it('ArrowDown wraps to first item from last', async () => {
 53→    const user = userEvent.setup();
 54→    const onChange = vi.fn();
 55→    renderList({ onActiveIndexChange: onChange });
 56→
 57→    await user.keyboard('{ArrowDown}{ArrowDown}{ArrowDown}');
 58→    expect(onChange).toHaveBeenLastCalledWith(0);
 59→  });
 60→
 61→  it('ArrowUp wraps to last item from first', async () => {
 62→    const user = userEvent.setup();
 63→    const onChange = vi.fn();
 64→    renderList({ onActiveIndexChange: onChange });
 65→
 66→    await user.keyboard('{ArrowUp}');
 67→    expect(onChange).toHaveBeenCalledWith(2);
 68→  });
 69→
 70→  it('ArrowUp moves active index backward', async () => {
 71→    const user = userEvent.setup();
 72→    renderList({});
 73→
 74→    await user.keyboard('{ArrowDown}{ArrowDown}{ArrowUp}');
 75→    const items = screen.getAllByRole('option');
 76→    expect(items[1]).toHaveAttribute('aria-selected', 'true');
 77→  });
 78→
 79→  it('Enter triggers onAction with active index', async () => {
 80→    const user = userEvent.setup();
 81→    const onAction = vi.fn();
 82→    renderList({ onAction });
 83→
 84→    await user.keyboard('{ArrowDown}');
 85→    await user.keyboard('{Enter}');
 86→    expect(onAction).toHaveBeenCalledWith(1);
 87→  });
 88→
 89→  it('does not navigate when modifier keys are pressed', async () => {
 90→    const user = userEvent.setup();
 91→    const onChange = vi.fn();
 92→    renderList({ onActiveIndexChange: onChange });
 93→
 94→    await user.keyboard('{Meta>}{ArrowDown}{/Meta}');
 95→    expect(onChange).not.toHaveBeenCalled();
 96→  });
 97→
 98→  it('does nothing when itemCount is 0', async () => {
 99→    const user = userEvent.setup();
100→    const onAction = vi.fn();
101→    renderList({
102→      itemCount: 0,
103→      onAction,
104→    });
105→
106→    await user.keyboard('{ArrowDown}');
107→    await user.keyboard('{Enter}');
108→    expect(onAction).not.toHaveBeenCalled();
109→  });
110→
111→  it('clamps active index when itemCount decreases', () => {
112→    const { rerender } = render(
113→      <List itemCount={3}>
114→        <ListItem index={0} title="A" />
115→        <ListItem index={1} title="B" />
116→        <ListItem index={2} title="C" />
117→      </List>,
118→    );
119→
120→    rerender(
121→      <List itemCount={1}>
122→        <ListItem index={0} title="A" />
123→      </List>,
124→    );
125→
126→    const items = screen.getAllByRole('option');
127→    expect(items[0]).toHaveAttribute('aria-selected', 'true');
128→  });
129→});
