  9→  const defaultProps = {
 10→    value: '',
 11→    onChange: vi.fn(),
 12→    ...props,
 13→  };
 14→  return {
 15→    ...render(<SearchBar {...defaultProps} />),
 16→    onChange: defaultProps.onChange,
