  7→
  8→function renderActionPanel(
  9→  overrides: {
 10→    actions?: Action[];
 11→    dropdownOpen?: boolean;
 12→    dropdownActions?: DropdownAction[];
 13→    onDropdownClose?: () => void;
 14→  } = {},
 15→) {
 16→  const defaultActions: Action[] = [
 17→    {
 18→      label: 'Open',
 19→      shortcut: <span>Enter</span>,
 20→      onClick: vi.fn(),
 21→    },
 22→    {
 23→      label: 'Copy',
 24→      shortcut: <span>⌘C</span>,
 25→      onClick: vi.fn(),
 26→    },
