  1→import { render, screen } from '@testing-library/react';
  2→import userEvent from '@testing-library/user-event';
  3→import { describe, expect, it, vi } from 'vitest';
  4→import type { DropdownAction } from './actions_dropdown';
  5→import { ActionsDropdown } from './actions_dropdown';
  6→
  7→function createActions(): DropdownAction[] {
  8→  return [
  9→    {
 10→      label: 'Copy URL',
 11→      shortcut: <span>⌘C</span>,
 12→      onClick: vi.fn(),
 13→    },
 14→    {
 15→      label: 'Delete',
 16→      shortcut: <span>⌘D</span>,
 17→      onClick: vi.fn(),
 18→    },
 19→    {
 20→      label: 'Move',
 21→      onClick: vi.fn(),
 22→    },
 23→  ];
 24→}
 25→
 26→function renderDropdown(
 27→  overrides: {
 28→    actions?: DropdownAction[];
 29→    open?: boolean;
 30→    onClose?: () => void;
 31→  } = {},
 32→) {
 33→  const actions = overrides.actions ?? createActions();
 34→  const onClose = overrides.onClose ?? vi.fn();
 35→  const result = render(
 36→    <ActionsDropdown
 37→      actions={actions}
 38→      open={overrides.open ?? true}
 39→      onClose={onClose}
 40→    />,
 41→  );
 42→  return {
 43→    ...result,
 44→    actions,
 45→    onClose,
 46→  };
 47→}
 48→
 49→describe('ActionsDropdown', () => {
 50→  it('renders nothing when closed', () => {
 51→    const { container } = renderDropdown({ open: false });
 52→    expect(container.innerHTML).toBe('');
 53→  });
 54→
 55→  it('renders nothing when actions are empty', () => {
 56→    const { container } = renderDropdown({
 57→      actions: [],
 58→      open: true,
 59→    });
 60→    expect(container.innerHTML).toBe('');
 61→  });
 62→
 63→  it('renders all actions when open', () => {
 64→    renderDropdown();
 65→    expect(screen.getByText('Copy URL')).toBeInTheDocument();
 66→    expect(screen.getByText('Delete')).toBeInTheDocument();
 67→    expect(screen.getByText('Move')).toBeInTheDocument();
 68→  });
 69→
 70→  it('renders shortcuts when provided', () => {
 71→    renderDropdown();
 72→    expect(screen.getByText('⌘C')).toBeInTheDocument();
 73→    expect(screen.getByText('⌘D')).toBeInTheDocument();
 74→  });
 75→
 76→  it('first item is active by default', () => {
 77→    renderDropdown();
 78→    const firstItem = screen.getByText('Copy URL').closest('button')!;
 79→    expect(firstItem).toHaveClass('actions-dropdown__item--active');
 80→  });
 81→
 82→  it('ArrowDown navigates to next item', async () => {
 83→    const user = userEvent.setup();
 84→    renderDropdown();
 85→
 86→    await user.keyboard('{ArrowDown}');
 87→    const secondItem = screen.getByText('Delete').closest('button')!;
 88→    expect(secondItem).toHaveClass('actions-dropdown__item--active');
 89→  });
 90→
 91→  it('ArrowDown wraps from last to first', async () => {
 92→    const user = userEvent.setup();
 93→    renderDropdown();
 94→
 95→    await user.keyboard('{ArrowDown}{ArrowDown}{ArrowDown}');
 96→    const firstItem = screen.getByText('Copy URL').closest('button')!;
 97→    expect(firstItem).toHaveClass('actions-dropdown__item--active');
 98→  });
 99→
100→  it('ArrowUp navigates to previous item', async () => {
101→    const user = userEvent.setup();
102→    renderDropdown();
103→
104→    await user.keyboard('{ArrowDown}{ArrowUp}');
105→    const firstItem = screen.getByText('Copy URL').closest('button')!;
106→    expect(firstItem).toHaveClass('actions-dropdown__item--active');
107→  });
108→
109→  it('ArrowUp wraps from first to last', async () => {
110→    const user = userEvent.setup();
111→    renderDropdown();
112→
113→    await user.keyboard('{ArrowUp}');
114→    const lastItem = screen.getByText('Move').closest('button')!;
115→    expect(lastItem).toHaveClass('actions-dropdown__item--active');
116→  });
117→
118→  it('Enter executes action and closes', async () => {
119→    const user = userEvent.setup();
120→    const { actions, onClose } = renderDropdown();
121→
122→    await user.keyboard('{Enter}');
123→    expect(actions[0]!.onClick).toHaveBeenCalledTimes(1);
124→    expect(onClose).toHaveBeenCalledTimes(1);
125→  });
126→
127→  it('Enter executes navigated action', async () => {
128→    const user = userEvent.setup();
129→    const { actions, onClose } = renderDropdown();
130→
131→    await user.keyboard('{ArrowDown}{Enter}');
132→    expect(actions[1]!.onClick).toHaveBeenCalledTimes(1);
133→    expect(onClose).toHaveBeenCalledTimes(1);
134→  });
135→
136→  it('Escape closes dropdown', async () => {
137→    const user = userEvent.setup();
138→    const { onClose } = renderDropdown();
139→
140→    await user.keyboard('{Escape}');
141→    expect(onClose).toHaveBeenCalledTimes(1);
142→  });
143→
144→  it('clicking action executes and closes', async () => {
145→    const user = userEvent.setup();
146→    const { actions, onClose } = renderDropdown();
147→
148→    await user.click(screen.getByText('Delete'));
149→    expect(actions[1]!.onClick).toHaveBeenCalledTimes(1);
150→    expect(onClose).toHaveBeenCalledTimes(1);
151→  });
